export function isValidPostalCode(code) {
  if (!code) return true; // non obligatoire
  // France : 5 chiffres, 01000 à 99999
  return /^[0-9]{5}$/.test(code);
}

import React, { useState, useEffect } from "react";
import InputField from "./InputField";
import { isValidPostalCode } from "@/utils/validators/postal_code";

export default function InputPostalCode({
  value,
  touched,
  required = false,
  submitted = false,
  ...props
}) {
  const [error, setError] = useState("");

  useEffect(() => {
    if ((touched || submitted)) {
      if (required && !value) {
        setError("Le code postal est obligatoire");
      } else if (value && !isValidPostalCode(value)) {
        setError("Code postal invalide");
      } else {
        setError("");
      }
    }
  }, [value, touched, submitted, required]);

  return (
    <InputField
      type="text"
      value={value}
      error={error}
      required={required}
      touched={touched}
      submitted={submitted}
      inputMode="numeric"   // clavier numérique sur mobile
      pattern="[0-9]*"      // restriction chiffres
      maxLength={5}         // 5 chiffres max
      {...props}
    />
  );
}

// frontend/src/utils/validators/email.js

/**
 * Vérifie si une chaîne est un email valide
 * @param {string} email
 * @returns {string|null} message d'erreur ou null si valide
 */
export function validateEmail(email) {
  if (!email || !email.trim()) return "L'email est obligatoire";

  // regex simple mais efficace pour la plupart des emails
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (!emailRegex.test(email)) return "Format d'email invalide";

  return null; // valide
}

/**
 * Vérifie si une chaîne est un email facultatif mais valide si renseigné
 * @param {string} email
 * @returns {string|null}
 */
export function validateOptionalEmail(email) {
  if (!email || !email.trim()) return null; // vide = ok
  return validateEmail(email);
}

import React, { useState, useEffect } from "react";
import InputField from "./InputField";
import { validateEmail, validateOptionalEmail } from "@/utils/validators/email";

export default function InputEmail({ value, touched, required = false, ...props }) {
  const [error, setError] = useState("");

  useEffect(() => {
    if (touched) {
      const validationError = required
        ? validateEmail(value)
        : validateOptionalEmail(value);
      setError(validationError);
    }
  }, [value, touched, required]);

  return (
    <InputField
      type="email"
      value={value}
      error={error}
      required={required}
      touched={touched}
      {...props}
    />
  );
}

// utils/validators/phone_number.js

/**
 * Vérifie si un numéro de téléphone est valide.
 * Non obligatoire : champ vide accepté.
 */
export function validatePhoneNumber(phoneValue) {
  if (!phoneValue) return null; // vide accepté

  const regex = /^\+?[0-9\s-]{6,20}$/;
  if (!regex.test(phoneValue)) return "Numéro de téléphone invalide";

  return null; // valide
}

import React, { useState, useEffect } from "react";
import InputField from "./InputField";
import { validatePhoneNumber } from "@/utils/validators/phone_number";

export default function InputPhone({ value, touched, required = false, ...props }) {
  const [error, setError] = useState("");

  useEffect(() => {
    if (touched) {
      const validationError = validatePhoneNumber(value);
      setError(validationError);
    }
  }, [value, touched]);

  return (
    <InputField
      type="tel"
      value={value}
      error={error}
      required={required}
      touched={touched}
      {...props}
    />
  );
}

// utils/validators/siret.js
export function isValidSiret(siret) {
  if (!/^\d{14}$/.test(siret)) return false;

  // Algorithme de Luhn
  let sum = 0;
  for (let i = 0; i < 14; i++) {
    let digit = parseInt(siret[i], 10);
    if (i % 2 === 0) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
  }
  return sum % 10 === 0;
}

