import React from "react";
import InputField from "./InputField";
import { isValidSiret } from "@/utils/validators/siret";

export default function InputSiret({
  value,
  touched = false,
  required = false,
  error = "",
  onChange,
  onBlur,
  ...props
}) {
  // L’erreur est entièrement gérée par le parent, plus besoin de state/useEffect
  const displayError =
    error ||
    (required && touched && !value
      ? "Le SIRET est obligatoire"
      : value && !isValidSiret(value)
      ? "SIRET invalide"
      : "");

  return (
    <InputField
      type="text"
      value={value}
      error={displayError}
      required={required}
      touched={touched}
      onChange={onChange}
      onBlur={onBlur}
      inputMode="numeric"   // clavier numérique sur mobile
      pattern="\d{14}"      // 14 chiffres
      maxLength={14}
      {...props}
    />
  );
}

import React from 'react';
import DatePicker, { registerLocale } from 'react-datepicker';
import { fr } from 'date-fns/locale/fr';
import 'react-datepicker/dist/react-datepicker.css';
import './DatePickerField.css'; // Pour les styles custom

// Enregistre la locale 'fr' pour l'utiliser dans le date-picker
registerLocale('fr', fr);

export function DatePickerField({ id, label, value, onChange, onBlur, error, required, disabled }) {
  // Pour éviter les soucis de fuseau horaire, on parse la date 'YYYY-MM-DD' manuellement.
  // new Date('2023-10-27') est interprété comme UTC, ce qui peut changer le jour.
  const selectedDate = (() => {
    if (!value) return null;
    const parts = value.split('-');
    // new Date(year, monthIndex, day) crée une date dans le fuseau horaire local.
    return new Date(parts[0], parseInt(parts[1], 10) - 1, parseInt(parts[2], 10));
  })();

  const handleChange = (date) => {
    // Le date-picker retourne un objet Date. On le formate en 'YYYY-MM-DD' pour le state parent.
    if (date) {
      // On utilise les getters qui respectent le fuseau horaire local.
      const year = date.getFullYear();
      const month = (date.getMonth() + 1).toString().padStart(2, '0');
      const day = date.getDate().toString().padStart(2, '0');
      onChange(`${year}-${month}-${day}`);
    } else {
      onChange(null);
    }
  };

  return (
    <div className="mb-3">
      <label htmlFor={id} className="form-label">
        {label} {required && <span className="required">*</span>}
      </label>
      <DatePicker
        id={id}
        selected={selectedDate}
        onChange={handleChange}
        onBlur={onBlur}
        dateFormat="dd/MM/yyyy"
        locale="fr"
        className={`form-control ${error ? 'is-invalid' : ''}`}
        placeholderText="jj/mm/aaaa"
        disabled={disabled}
        autoComplete="off"
      />
      {error && <div className="invalid-feedback">{error}</div>}
    </div>
  );
}

export function CheckboxField({ id, name, label, checked, onChange, disabled }) {
  return (
    <div className="form-check mb-2">
      <input
        type="checkbox"
        className="form-check-input"
        id={id}
        name={name}
        checked={checked}
        onChange={onChange}
        disabled={disabled}
      />
      <label className="form-check-label" htmlFor={id}>
        {label}
      </label>
    </div>
  );
}

import { useState } from 'react';
import { Eye, EyeOff } from 'lucide-react';

export default function PasswordInput({ id, name, label, value, onChange, disabled, error, helpText }) {
  const [show, setShow] = useState(false);

  return (
    <div className="relative w-full">
      <label htmlFor={id} className="block mb-1 font-medium text-gray-700">{label}</label>
      <input
        type={show ? 'text' : 'password'}
        id={id}
        name={name}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        disabled={disabled}
        className={`border p-2 w-full rounded-md pr-10 focus:outline-none focus:ring-2 focus:ring-blue-400 focus:border-blue-400 ${
          error ? 'border-red-500' : 'border-gray-300'
        }`}
      />
      <button
        type="button"
        onClick={() => setShow(!show)}
        className="absolute right-2 top-1/2 -translate-y-1/2 bg-gray-100 hover:bg-gray-200 text-gray-600 hover:text-gray-900 rounded-full p-1 transition-all duration-200 shadow-sm"
        aria-label={show ? 'Masquer le mot de passe' : 'Afficher le mot de passe'}
      >
        {show ? <EyeOff size={18} /> : <Eye size={18} />}
      </button>
      {helpText && <p className="text-sm text-gray-500 mt-1">{helpText}</p>}
      {error && <p className="text-sm text-red-500 mt-1">{error}</p>}
    </div>
  );
}

// frontend/src/components/form/CreatableSelect.jsx
import React from "react";
import Creatable from "react-select/creatable";

export default function CreatableSelect({
  id,
  name,
  label,
  value,
  onChange,
  onBlur,
  error = "",
  required = false,
  disabled = false,
  placeholder = "",
  options = [],
  isClearable = true,
  formatCreateLabel,
  feedbackText = "",     // Texte à afficher en dessous
  feedbackClass = "",    // Classe CSS du feedback (ex: "text-success" ou "text-warning")
  ...props
}) {
  const showError = Boolean(error) || (required && !value);

  return (
    <div className="mb-3">
      {label && (
        <label htmlFor={id || name} className="form-label">
          {label} {required && "*"}
        </label>
      )}

      <Creatable
        id={id || name}
        name={name}
        value={value}
        onChange={onChange}
        onBlur={() => onBlur?.(name)}
        options={options}
        isClearable={isClearable}
        isDisabled={disabled}
        placeholder={placeholder}
        formatCreateLabel={formatCreateLabel}
        styles={{
          control: (provided, state) => ({
            ...provided,
            backgroundColor: state.isDisabled ? "#e8ebeefa" : "#fff",
            borderColor: showError ? "#dc3545" : "#ced4da",
            boxShadow: state.isFocused
              ? "0 0 0 0.2rem rgba(0,123,255,.25)"
              : "none",
            "&:hover": { borderColor: "#adb5bd" },
          }),
          singleValue: (provided) => ({ ...provided, color: "#212529" }),
          input: (provided) => ({ ...provided, color: "#212529" }),
          placeholder: (provided) => ({ ...provided, color: "#6c757d" }),
          menu: (provided) => ({ ...provided, backgroundColor: "#fff", zIndex: 9999 }),
        }}
        {...props}
      />

      {showError && (
        <small className="text-danger">{error || "Ce champ est obligatoire"}</small>
      )}

      {!showError && feedbackText && (
        <small className={feedbackClass}>{feedbackText}</small>
      )}
    </div>
  );
}

